<template>
	<view class="page">
		<view class="title">{{ detail.title }}</view>
		<view class="meta">{{ formatTime(detail.publishedAt || detail.createdAt) }}</view>
		<view class="content">{{ detail.content }}</view>
	</view>
</template>

<script>
import { getNewsDetail, toAbsoluteUrl } from '@/utils/api.js'

export default {
	data() {
		return {
			id: null,
			detail: {}
		}
	},
	onLoad(query) {
		this.id = Number(query?.id) || null
		if (this.id) this.load()
		else uni.showToast({ title: '参数错误', icon: 'none' })
	},
	methods: {
		absUrl: toAbsoluteUrl,
		formatTime(ts) {
			if (!ts) return ''
			const d = new Date(ts)
			const p = (n) => (n < 10 ? '0' + n : n)
			return `${d.getFullYear()}-${p(d.getMonth()+1)}-${p(d.getDate())} ${p(d.getHours())}:${p(d.getMinutes())}`
		},
		async load() {
			try {
				const res = await getNewsDetail(this.id)
				const payload = res && res.data ? res.data.data : null
				this.detail = payload || {}
			} catch (e) {
				uni.showToast({ title: '加载失败', icon: 'none' })
			}
		}
	}
}
</script>

<style scoped>
.page { padding: 16px; }
.title { font-size: 20px; font-weight: 700; color: #222; }
.meta { font-size: 12px; color: #999; margin: 8px 0 12px; }
.content { font-size: 16px; color: #333; line-height: 1.7; word-break: break-all; }
</style>

